{
  "title": "Spicy Pineapple Chicken Tacos",
  "description": "Spicy pineapple chicken tacos featuring marinated chicken, a vibrant pineapple-jalapeño salsa, and warm tortillas. This recipe balances sweet, spicy, and tangy flavors for a fresh and satisfying meal.",
  "servings": 4,
  "prep_time_min": 20,
  "cook_time_min": 15,
  "difficulty": "intermediate",
  "ingredients": [
    {
      "name": "chicken breast or thighs",
      "quantity": 1.5,
      "unit": "lb",
      "prep": "boneless, skinless, cut into 1-inch pieces"
    },
    {
      "name": "lime juice",
      "quantity": 2,
      "unit": "tbsp",
      "prep": "freshly squeezed"
    },
    {
      "name": "garlic",
      "quantity": 3,
      "unit": "cloves",
      "prep": "minced"
    },
    {
      "name": "chili powder",
      "quantity": 1,
      "unit": "tsp",
      "prep": null
    },
    {
      "name": "salt",
      "quantity": 0.5,
      "unit": "tsp",
      "prep": null
    },
    {
      "name": "black pepper",
      "quantity": 0.25,
      "unit": "tsp",
      "prep": "freshly ground"
    },
    {
      "name": "olive oil",
      "quantity": 1,
      "unit": "tbsp",
      "prep": null
    },
    {
      "name": "fresh pineapple",
      "quantity": 1.5,
      "unit": "cups",
      "prep": "diced"
    },
    {
      "name": "jalapeño",
      "quantity": 1,
      "unit": null,
      "prep": "finely diced (remove seeds for less heat)"
    },
    {
      "name": "red onion",
      "quantity": 0.25,
      "unit": "cup",
      "prep": "finely diced"
    },
    {
      "name": "cilantro",
      "quantity": 0.25,
      "unit": "cup",
      "prep": "chopped"
    },
    {
      "name": "lime juice",
      "quantity": 1,
      "unit": "tbsp",
      "prep": "freshly squeezed, for salsa"
    },
    {
      "name": "salt",
      "quantity": 0.25,
      "unit": "tsp",
      "prep": "for salsa"
    },
    {
      "name": "corn or flour tortillas",
      "quantity": 12,
      "unit": null,
      "prep": "small"
    },
    {
      "name": "avocado",
      "quantity": 1,
      "unit": null,
      "prep": "sliced or diced"
    }
  ],
  "steps": [
    {
      "text": "In a medium bowl, combine the diced chicken, 2 tablespoons lime juice, minced garlic, chili powder, 1/2 teaspoon salt, and black pepper. Stir to ensure the chicken is evenly coated. Marinate for at least 15 minutes, or up to 30 minutes in the refrigerator."
    },
    {
      "text": "While the chicken marinates, prepare the pineapple-jalapeño salsa. In a separate bowl, combine the diced fresh pineapple, finely diced jalapeño, finely diced red onion, chopped cilantro, 1 tablespoon lime juice, and 1/4 teaspoon salt. Stir gently and set aside
